from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum

class SLAStatus(str, Enum):
    OK        = "ok"
    WARNING   = "warning"   # > 80% of window elapsed
    BREACHED  = "breached"

@dataclass
class TicketSLATracker:
    ticket_id: str
    customer_tier: str
    opened_at: datetime
    current_priority: str
    first_response_at: datetime | None = None
    resolved_at: datetime | None = None
    priority_history: list[tuple[str, datetime]] = field(default_factory=list)

    def _sla_def(self) -> SLADefinition:
        # Looks up SLA from tier + priority
        return ENTERPRISE_SLAS.get(self.current_priority)

    def first_response_status(self, as_of: datetime | None = None) -> SLAStatus:
        ref = as_of or datetime.utcnow()
        if self.first_response_at is not None:
            return SLAStatus.OK
        sla = self._sla_def()
        if sla is None:
            return SLAStatus.OK
        deadline = sla.first_response_deadline(self.opened_at)
        if ref >= deadline:
            return SLAStatus.BREACHED
        warning_at = self.opened_at + (deadline - self.opened_at) * 0.8
        if ref >= warning_at:
            return SLAStatus.WARNING
        return SLAStatus.OK

    def is_first_response_breached(self, as_of: datetime | None = None) -> bool:
        return self.first_response_status(as_of) == SLAStatus.BREACHED

    def minutes_to_first_response_breach(self, as_of: datetime | None = None) -> float | None:
        """Returns None if already responded or no SLA defined.""\"
        if self.first_response_at is not None:
            return None
        sla = self._sla_def()
        if sla is None:
            return None
        ref = as_of or datetime.utcnow()
        deadline = sla.first_response_deadline(self.opened_at)
        return max(0, (deadline - ref).total_seconds() / 60)

from datetime import datetime, timedelta, time
from zoneinfo import ZoneInfo
from dataclasses import dataclass, field

BUSINESS_START = time(9, 0)   # 09:00 support team local time
BUSINESS_END   = time(18, 0)  # 18:00 support team local time
SUPPORT_TZ     = ZoneInfo("America/Los_Angeles")

@dataclass
class SLAClock:
    ticket_id: str
    sla_hours: float
    business_hours_only: bool
    opened_at: datetime              # must be tz-aware UTC
    pauses: list[tuple[datetime, datetime | None]] = field(default_factory=list)

    # --- pause management ---

    def pause(self, at: datetime) -> None:
        """Start a pause (e.g. waiting-on-customer)."""
        self.pauses.append((at, None))

    def resume(self, at: datetime) -> None:
        """End the most recent open pause."""
        for i in range(len(self.pauses) - 1, -1, -1):
            start, end = self.pauses[i]
            if end is None:
                self.pauses[i] = (start, at)
                return
        raise ValueError("No open pause to resume")

    # --- elapsed calculation ---

    def _paused_seconds(self, as_of: datetime) -> float:
        total = 0.0
        for start, end in self.pauses:
            effective_end = end if end is not None else as_of
            if effective_end > start:
                total += (effective_end - start).total_seconds()
        return total

    def elapsed_hours(self, as_of: datetime | None = None) -> float:
        ref = as_of or datetime.now(tz=ZoneInfo("UTC"))
        raw_seconds = (ref - self.opened_at).total_seconds()
        paused = self._paused_seconds(ref)
        net_seconds = max(0.0, raw_seconds - paused)
        if not self.business_hours_only:
            return net_seconds / 3600
        # Business-hours calculation: walk from opened_at to ref in support TZ
        return self._business_hours_elapsed(
            self.opened_at.astimezone(SUPPORT_TZ),
            ref.astimezone(SUPPORT_TZ),
        ) - paused / 3600

    @staticmethod
    def _business_hours_elapsed(start: datetime, end: datetime) -> float:
        if end <= start:
            return 0.0
        total = 0.0
        cursor = start
        while cursor.date() <= end.date():
            if cursor.weekday() < 5:  # Mon–Fri only
                day_start = cursor.replace(
                    hour=BUSINESS_START.hour, minute=0, second=0, microsecond=0
                )
                day_end = cursor.replace(
                    hour=BUSINESS_END.hour, minute=0, second=0, microsecond=0
                )
                window_start = max(cursor, day_start)
                window_end   = min(end, day_end)
                if window_end > window_start:
                    total += (window_end - window_start).total_seconds() / 3600
            cursor = (cursor + timedelta(days=1)).replace(
                hour=0, minute=0, second=0, microsecond=0
            )
        return total

    def deadline(self) -> datetime:
        """Wall-clock UTC time when the SLA expires (approximate for business-hours)."""
        # For 24/7 SLAs: straightforward addition accounting for pauses.
        # For business-hours SLAs: add business-hour blocks from opened_at.
        paused = self._paused_seconds(datetime.now(tz=ZoneInfo("UTC")))
        if not self.business_hours_only:
            return self.opened_at + timedelta(hours=self.sla_hours) + timedelta(seconds=paused)
        # Walk forward counting only business hours
        target = self.sla_hours
        cursor = self.opened_at.astimezone(SUPPORT_TZ)
        while target > 0:
            if cursor.weekday() < 5:
                day_end = cursor.replace(
                    hour=BUSINESS_END.hour, minute=0, second=0, microsecond=0
                )
                available = max(0.0, (day_end - cursor).total_seconds() / 3600)
                if available >= target:
                    cursor += timedelta(hours=target)
                    target = 0
                else:
                    target -= available
                    cursor += timedelta(days=1)
                    cursor = cursor.replace(
                        hour=BUSINESS_START.hour, minute=0, second=0, microsecond=0
                    )
            else:
                cursor += timedelta(days=1)
                cursor = cursor.replace(
                    hour=BUSINESS_START.hour, minute=0, second=0, microsecond=0
                )
        deadline_local = cursor + timedelta(seconds=paused)
        return deadline_local.astimezone(ZoneInfo("UTC"))
